-- Sync raw_ingredients + packs + supplier links from master sheet (generated by scripts/generate_028_master_sync.py).
-- Requires 027 (pack_purpose, display_unit_label). Re-run after editing the TSV in that script.
--
-- Rules:
--   - Base raw_ingredients.unit: g (weight), ml (volume), pcs (countables incl. rolls as counted units).
--   - stocktake pack: pack_purpose = stocktake (or both if no separate order pack).
--   - order pack: pack_purpose = order when ordering_* filled; else single pack with both.
--   - Multi-supplier: "Bidfood; Van Gelder" → multiple supplier_ingredients rows.
--   - weekly=1 → order_interval_days = 7; stocktake_day_of_week = 1 (Monday) until sheet has a weekday column.
--   - visible=0 → stocktake_visible = false (master I). supplier_ingredients.is_preferred uses the same flag.
--   - One pass per location: FOR loc_id IN SELECT id FROM locations.
--   - Master B,C,D also on raw_ingredients (stocktake_* mirror) so stocktake UI works without pack rows.

ALTER TABLE raw_ingredients
  ADD COLUMN IF NOT EXISTS order_interval_days INTEGER NULL;

ALTER TABLE raw_ingredients
  ADD COLUMN IF NOT EXISTS stocktake_visible BOOLEAN NOT NULL DEFAULT true;

ALTER TABLE raw_ingredients
  ADD COLUMN IF NOT EXISTS stocktake_day_of_week SMALLINT NULL;

ALTER TABLE raw_ingredients
  ADD COLUMN IF NOT EXISTS stocktake_unit_label TEXT NULL;

ALTER TABLE raw_ingredients
  ADD COLUMN IF NOT EXISTS stocktake_content_amount NUMERIC NULL;

ALTER TABLE raw_ingredients
  ADD COLUMN IF NOT EXISTS stocktake_content_unit TEXT NULL;

ALTER TABLE ingredient_pack_sizes
  ADD COLUMN IF NOT EXISTS grams_per_piece NUMERIC NULL;

DO $$
DECLARE
  loc_id UUID;
  rid UUID;
  sup_id UUID;
BEGIN
  FOR loc_id IN SELECT id FROM locations
  LOOP
    -- Onion peeled
    SELECT id INTO rid FROM raw_ingredients WHERE location_id = loc_id AND lower(btrim(name)) = lower(btrim('Onion peeled')) LIMIT 1;
    IF rid IS NULL THEN
      INSERT INTO raw_ingredients (location_id, name, unit, order_interval_days, stocktake_visible, stocktake_day_of_week, stocktake_unit_label, stocktake_content_amount, stocktake_content_unit)
      VALUES (loc_id, 'Onion peeled', 'g', NULL, TRUE, NULL, 'bag', 1.0, 'kg')
      RETURNING id INTO rid;
    ELSE
      UPDATE raw_ingredients SET unit = 'g', order_interval_days = NULL, stocktake_visible = TRUE, stocktake_day_of_week = NULL, stocktake_unit_label = 'bag', stocktake_content_amount = 1.0, stocktake_content_unit = 'kg', updated_at = NOW() WHERE id = rid;
    END IF;

    DELETE FROM ingredient_pack_sizes WHERE raw_ingredient_id = rid;

    INSERT INTO ingredient_pack_sizes (raw_ingredient_id, size, size_unit, pack_purpose, display_unit_label)
    VALUES (rid, 1.0, 'kg', 'both', 'bag');

    DELETE FROM supplier_ingredients WHERE raw_ingredient_id = rid;

    INSERT INTO suppliers (location_id, name)
    SELECT loc_id, 'Van Gelder' WHERE NOT EXISTS (SELECT 1 FROM suppliers s WHERE s.location_id = loc_id AND lower(btrim(s.name)) = lower(btrim('Van Gelder')));

    SELECT id INTO sup_id FROM suppliers WHERE location_id = loc_id AND lower(btrim(name)) = lower(btrim('Van Gelder')) LIMIT 1;
    INSERT INTO supplier_ingredients (supplier_id, raw_ingredient_id, is_preferred)
    VALUES (sup_id, rid, true)
    ON CONFLICT (supplier_id, raw_ingredient_id) DO UPDATE SET is_preferred = EXCLUDED.is_preferred, updated_at = NOW();

    -- Tomato
    SELECT id INTO rid FROM raw_ingredients WHERE location_id = loc_id AND lower(btrim(name)) = lower(btrim('Tomato')) LIMIT 1;
